package com.gorunjinian.metrovault.bitcoin

import com.gorunjinian.metrovault.lib.bitcoin.ByteVector
import com.gorunjinian.metrovault.lib.bitcoin.ParseFailure
import com.gorunjinian.metrovault.lib.bitcoin.Psbt
import com.gorunjinian.metrovault.lib.bitcoin.utils.Either
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNotNull
import org.junit.Assert.assertTrue
import org.junit.Test

// focus on parsing-failure detection (no script verification needed)
class PsbtParsingTest {

    private fun assertParseFails(expected: ParseFailure, hex: String) {
        val result = Psbt.read(ByteVector(hex))
        assertTrue("expected Left, got $result", result is Either.Left)
        assertEquals(expected, (result as Either.Left).value)
    }

    private fun assertParseFailsWithKind(expectedKind: Class<out ParseFailure>, hex: String) {
        val result = Psbt.read(ByteVector(hex))
        assertTrue("expected Left, got $result", result is Either.Left)
        val value = (result as Either.Left).value
        assertTrue(
            "expected ${expectedKind.simpleName}, got ${value::class.simpleName} ($value)",
            expectedKind.isInstance(value)
        )
    }

    @Test
    fun networkTxNotPsbtFormat() {
        // A raw network tx (no PSBT magic) should be rejected.
        assertParseFails(
            ParseFailure.InvalidMagicBytes,
            ""
        )
    }

    @Test
    fun psbtMissingOutputs() {
        assertParseFails(
            ParseFailure.InvalidContent,
            ""
        )
    }

    @Test
    fun psbtUnsignedTxHasNonEmptyScriptSig() {
        // Global unsigned tx must have empty scriptSigs and witnesses on each input.
        assertParseFailsWithKind(
            ParseFailure.InvalidGlobalTx::class.java,
            ""
        )
    }

    @Test
    fun psbtMissingGlobalTx() {
        // Inputs and outputs supplied but global tx field is absent.
        assertParseFails(
            ParseFailure.GlobalTxMissing,
            ""
        )
    }

    @Test
    fun psbtDuplicateKeysInInput() {
        assertParseFails(
            ParseFailure.DuplicateKeys,
            ""
        )
    }

    @Test
    fun psbtInvalidGlobalTxKey() {
        assertParseFailsWithKind(
            ParseFailure.InvalidGlobalTx::class.java,
            ""
        )
    }

    @Test
    fun psbtInvalidWitnessUtxoKey() {
        assertParseFailsWithKind(
            ParseFailure.InvalidTxInput::class.java,
            ""
        )
    }

    @Test
    fun psbtInvalidTaprootInternalKeyLength() {
        // Taproot internal key entry must be exactly 32 bytes (X-only).
        assertParseFailsWithKind(
            ParseFailure.InvalidTxInput::class.java,
            ""
        )
    }

    @Test
    fun psbtInvalidTaprootKeyPathSignatureLength() {
        // Taproot keypath signature must be 64 or 65 bytes.
        assertParseFailsWithKind(
            ParseFailure.InvalidTxInput::class.java,
            ""
        )
    }

    @Test
    fun psbtMissingInputs() {
        assertParseFails(
            ParseFailure.InvalidContent,
            "70736274ff0100750200000001268171371edff285e937adeea4b37b78000c0566cbb3ad64641713ca42171bf60000000000feffffff02d3dff505000000001976a914d0c59903c5bac2868760e90fd521a4665aa7652088ac00e1f5050000000017a9143545e6e33b832c47050f24d3eeb93c9c03948bc787b32e1300000000"
        )
    }

    @Test
    fun psbtUnsignedTxWithWitnessSerialization() {
        // The global unsigned tx must be serialized in non-witness format.
        assertParseFailsWithKind(
            ParseFailure.InvalidGlobalTx::class.java,
            ""
        )
    }

    @Test
    @Suppress("UNUSED_VARIABLE")
    fun parseFailureTypesAreReachable() {
        // Compile-time presence check for the ParseFailure surface we depend on for future tests.
        assertNotNull(ParseFailure.InvalidMagicBytes)
        assertNotNull(ParseFailure.InvalidContent)
        assertNotNull(ParseFailure.DuplicateKeys)
        assertNotNull(ParseFailure.GlobalTxMissing)
    }
}
